                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , scwin.param                     // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , scwin.check                     // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );*/
    await udc_retrieveCompanyInfo.cfCommonPopUp(scwin.udc_coCd_callBackFunc
    									,ed_coCd.getValue(), ""
    									,pWinCloseTF,null,null,null,null
    									,null,null,null,null,null); 

	if(ed_coCd.getValue() > ACConstants.CO_CD_DONGBU)  { // 자회사 회계 시스템 
		scwin.isSubCompany = true;
	} else {
		scwin.isSubCompany = false;
	}

    scwin.f_showLoexDistYn();
}

scwin.f_showLoexDistYn = function (){
    if (ed_coCd.getValue() == "000") {//로엑스의 경우 (로엑스)배부포함 hidden
        // document.getElementById("td_loexDistYn").style.display = "none";
        // chk_loexDistYn.hide("");
    } else {
        // document.getElementById("td_loexDistYn").style.display = "block";
        // chk_loexDistYn.show("");
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업  callBackFunc
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function(ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_coCd.setValue(ret[0]);  // 코드
        ed_coNm.setValue(ret[5]);  // 회사명
    } else {
        ed_coCd.setValue("");  // 코드
        ed_coNm.setValue("");  // 회사명
    }

    // 자회사 회계 시스템(?-txtCoClsCd : As-Is HiddenField였음 )
    if (scwin.vLoginCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {        
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }     
};

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_acctDeptCdPopUp = function(e) {
    var param = ",04";
    var check = $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) ? "F" : "T";

    var pW = "410";

    //<--<수정_070105_신종민> 귀속변경에 따른 병행처리 수정
    if ( ed_srchCloseYm.getValue().substring(0,4).trim() == "2006" ){
        udc_acctDeptCdInfo.setSelectId("retrieveAcctDeptCdInfoBef");
    }else{
        udc_acctDeptCdInfo.setSelectId("retrieveAcctDeptCdInfo");
    };

    udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc
                    , ed_srchAcctDeptCd.getValue()
                    , ""
                    , check                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                    , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                    , null                            // Title순서
                    , null                            // 보여주는 각 컬럼들의 폭
                    , null                            // 컬럼중에서 숨기는 컬럼 지정
                    , dma_search.get("closeYm")+",,,,,,,,,"+ed_coCd.getValue()                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                    , pW                              // POP-UP뛰을때 원도우의 사용자 정의 폭
                    , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                    , null                            // 윈도우 위치 Y좌표
                    , null                            // 윈도우 위치 X좌표
                    , null                            // 중복체크여부	("F")
                    , null                             // 전체검색허용여부	("F")
                    , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                    ); 
}

