        // console.log("=================> ret[0]:"+ret[0]);
        // ds_search.set("acctDeptLvl", ret[6]); // 귀속부서레벨
        scwin.tacctDeptLvl = ret[6];
        // lc_acctDeptCd.setValue(ret[0]);
        // scwin.p_acctDeptCd = ret[0];
	} else {
        ed_srchAcctDeptCd.setValue("");
        ed_srchAcctDeptNm.setValue("");

        // ds_search.set("acctDeptLvl", 0); // 귀속부서레벨
        scwin.tacctDeptLvl = 0;  
        lc_acctDeptCd.setValue("");
        scwin.p_acctDeptCd = "";
	}
}

//-------------------------------------------------------------------------
// 사업영역코드팝업
//-------------------------------------------------------------------------
scwin.f_BizDomPopUp = async function(e) {

    var pW = "410";     
    var param = "";
    var check = $c.gus.cfIsNull(ed_bizDomCd.getValue()) ? "F" : "T";

    udc_bizDomCd.cfCommonPopUp(scwin.udc_bizDomCd_callBackFunc
                        , ed_bizDomCd.getValue().trim()
                        , null
                        , check                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                     // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , pW                        // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                    // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
}
//-------------------------------------------------------------------------
// 사업영역코드팝업 callBackFunc
//-------------------------------------------------------------------------
scwin.udc_bizDomCd_callBackFunc = function(ret) {      
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_bizDomCd.setValue(ret[0]);  
        ed_bizDomNm.setValue(ret[1]);
    } else {
        ed_bizDomCd.setValue("");
        ed_bizDomNm.setValue("");
    }    
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if (!$c.gus.cfValidate([tbl_search])) return;

    // 버전이 001일경우는 장부구분의 (자산비용)을 조회 하도록 코드값을 변경한다.
    if ( lc_version.getValue() == "001" || lc_version.getValue() == "000" ) {
        // 일반일경우
        if ( lc_srchBookClsCd.getValue() == "601" ) {
              dma_search.set("bookClsCd", "621");   
        // 요약일경우
        } else if ( lc_srchBookClsCd.getValue() == "602" ) {
              dma_search.set("bookClsCd", "622");
        // 상세일경우
        } else if ( lc_srchBookClsCd.getValue() == "603" ) {
              dma_search.set("bookClsCd", "623");
        }
    }

    gr_master.setNoResultMessageVisible(false);
    ds_master.reform();
    ds_master.removeAll();
    totalRows.setValue("0");
    dma_search.set("acctDeptCd", lc_acctDeptCd.getValue());

    // console.log("=============> scwin.p_acctDeptCd:"+scwin.p_acctDeptCd+", lc_acctDeptCd.getValue():"+lc_acctDeptCd.getValue()+", acctDeptCd:"+dma_search.get("acctDeptCd"));
    dma_search.set("acctDeptCd", lc_acctDeptCd.getValue());  

    let e = await $c.sbm.execute(sbm_master);
    scwin.sbm_master_submitdone(e);
}

