//-------------------------------------------------------------------------
// 실적부서를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetRsltsDept = async function () {
     gr_master.initGrid();

     lc_acctDeptCd.setDisabled(false);
     dma_search.set("fromDate", scwin.fromDate_Ym);
     dma_search.set("bookClsCd", lc_srchBookClsCd.getValue());  
     dma_search.set("ver", lc_version.getValue()); 
     dma_search.set("closeYm", ed_srchCloseYm.getValue());
     dma_search.set("acctDeptCd", ed_srchAcctDeptCd.getValue());
     dma_search.set("coCd", ed_coCd.getValue());    
     dma_search.set("eisAcctDeptCd","0");
     dma_search.set("distYn", scwin.tDistYn);   // 배부포함
     dma_search.set("dpctYn", "0");    // DPCT 여부
     dma_search.set("exceptionDeptYn", 0);     
     dma_search.set("bizDomCd", ed_bizDomCd.getValue());
     dma_search.set("lowerDeptIncluYn", scwin.tldily);  // 하위부서포함
     dma_search.set("acctDeptLvl", scwin.tacctDeptLvl);
     dma_search.set("pageNo", 0);         
     dma_search.set("clsCd", "");        
     dma_search.set("CloseYyMm", ed_srchCloseYm.getValue()); 
     // eisAcctDeptCd : 0 일때 월별추이실적조회 , 1:법인별손익추이, 2:사업영역별손익추이
     console.log("======ed_bizDomCd:"+ed_bizDomCd.getValue()+", bizDomCd:"+dma_search.get("bizDomCd"));

    if (!await $c.gus.cfValidate([tbl_search])) return;  	

    if (ed_bizDomCd.getValue() == ""){

        dma_dept.set("sysCd", "ManagementProfitAndLossEBC");
        dma_dept.set("queryId", "retrievePlanComparisonResultsAcctDept");
        dma_dept.set("param1", ed_srchAcctDeptCd.getValue());
        dma_dept.set("param2", dma_search.get("closeYm"));

        dma_dept.set("param3", dma_search.get("lowerDeptIncluYn"));
        dma_dept.set("param4", dma_search.get("acctDeptLvl"));
        dma_dept.set("param5", dma_search.get("ver"));
        dma_dept.set("param6", dma_search.get("dpctYn"));

/**ds_dept_search.set("param3", ds_searchMonthCostResult.get("lowerDeptIncluYn"));
        ds_dept_search.set("param4", ds_searchMonthCostResult.get("acctDeptLvl"));
        ds_dept_search.set("param5", ds_searchMonthCostResult.get("ver"));*/

        dma_dept.set("param7", ed_coCd.getValue());
        console.log("==============> ed_coCd.getValue():"+ed_coCd.getValue()+", ed_srchAcctDeptCd.getValue():"+ed_srchAcctDeptCd.getValue());
        var rs = await $c.sbm.execute(sbm_dept);
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            ds_dept.setJSON(rs.responseJSON.GAUCE);
            ds_dept.sort("col1", 0);
            var rowCnt = ds_dept.getRowCount();
            if (rowCnt < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
                return;
            }
            scwin.f_Retrieve();
        };

    } else {

        dma_dept.set("sysCd", "ManagementProfitAndLossEBC");
        dma_dept.set("queryId", "retrievePlanComparisonResultsBizDom");
        dma_dept.set("param1", ed_srchAcctDeptCd.getValue());
        dma_dept.set("param2", dma_search.get("closeYm"));
        dma_dept.set("param3", dma_search.get("lowerDeptIncluYn"));
        dma_dept.set("param4", dma_search.get("acctDeptLvl"));
        // dma_dept.set("param5", ed_BizDomCd.getValue());
        dma_dept.set("param5", dma_search.get("bizDomCd"));
        dma_dept.set("param6", dma_search.get("dpctYn"));
        dma_dept.set("param7", ed_coCd.getValue());
        var rs = await $c.sbm.execute(sbm_dept);
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            ds_dept.setJSON(rs.responseJSON.GAUCE);
            ds_dept.sort("col1", 0);
            var rowCnt = ds_dept.getRowCount();
            if (rowCnt < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
                return;
            }
            scwin.f_Retrieve();
        };
    }
};

