scwin.btn_search_onclick = async function (e) {
//    ret = await $c.gus.cfValidate([ed_coCd, lc_srchBookClsCd, ed_srchCloseYm, lc_version, ed_srchAcctDeptCd]);
//    if (!ret) {       
//       $c.gus.cfAlertMsg(MSG_CM_ERR_002);
//       return;            
//    } 
    if(ed_coCd.getValue().trim().length <= 0){
        await $c.win.alert("회사코드는 필수입력항목입니다.");
        return;
    }    
    if(lc_srchBookClsCd.getValue().trim().length <= 0){
        await $c.win.alert("장부구분은 필수입력항목입니다.");
        return;
    }
    if(ed_srchCloseYm.getValue().trim().length <= 0){
        await $c.win.alert("결산년월은 필수입력항목입니다.");
        return;
    }       
    if(lc_version.getValue().trim().length <= 0){
        await $c.win.alert("버전은 필수입력항목입니다.");
        return;
    }    
    if(ed_srchAcctDeptCd.getValue().trim().length <= 0){
        await $c.win.alert("부서코드는 필수입력항목입니다.");
        return;
    }    
    scwin.f_GetRsltsDept();
};

