scwin.f_Retrieve2 = async function () {

    if (ds_dept.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    if ( dma_search.get("closeYm") < "200600" ) {
        dma_search.set("closeYmYn", "1");
    } else {
        dma_search.set("closeYmYn", "0");
    }

    let bookClsCd = lc_srchBookClsCd.getValue();
    let ver = lc_version.getValue();

    // 버전이 001일경우는 장부구분의 (자산비용)을 조회 하도록 코드값을 변경한다.
    if ( ver === "001" || ver === "000" ) {
        // 일반일경우
        if ( bookClsCd === "601" ) {
            dma_search.set("bookClsCd","621");
        // 요약일경우
        } else if ( bookClsCd === "602" ) {
            dma_search.set("bookClsCd","622");
        // 상세일경우
        } else if ( bookClsCd === "603" ) {
            dma_search.set("bookClsCd","623");
        }
    }

    gen_gridView1.removeAll();    
    scwin.f_Export2();
    // console.log("===>ds_dept.getRowCount():"+ds_dept.getRowCount());
    // for (let i = ds_dept.getRowCount()-1; i >= 0 ; i-- ){
    //     // ds_search.NameString(ds_search.RowPosition, "acctDeptCd") = ds_dept.NameString(i,"COL1")
    //     dma_search.set("acctDeptCd", ds_dept.getCellData(i, "col1"));
    //     await scwin.f_ExportGoTo(ds_dept.getCellData(i, "col2"));
    // }
}

scwin.f_ExportGoTo = async function (acctDeptCd) {
    // if( ds_dept.NameString(ds_dept.CountRow,"COL2") == acctDeptCd ) {
        // console.log("==============> acctDeptCd:"+acctDeptCd+", col2:"+ds_dept.getCellDatads_dept.getRowPosition(), "col2"));
        if( ds_dept.getCellData(ds_dept.getRowPosition(), "col2") == acctDeptCd ) {
            let e = await $c.sbm.execute(sbm_master);
            scwin.sbm_master_submitdone(e);
            // console.log("===>ds_dept.col1:"+ds_dept.getCellData(i, "col1")+", ds_dept.col2:"+ds_dept.getCellData(i, "col2"));
            await scwin.f_Export2_one(acctDeptCd);
        } else {
            gen_gridView1.removeAll();    
            scwin.f_Export2();
        }
}

scwin.f_Export2_one = async function(acctDeptCd) {
    if (ds_master.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    let str1 = $c.gus.cfGetFormatStr(ed_srchCloseYm.getValue(), "######");
    let sheetTitle = acctDeptCd + "(" + str1 + ")";
    let sheetTitle2 = '단위_' + lc_unit.getText(true);
    let colCount = gr_master.getTotalCol();

    let infoArr = [{
        rowIndex : 0, 
        colIndex : 0, 
        rowSpan : 1,
        colSpan : colCount, 
        text : sheetTitle, 
        textAlign : "center",
        // fontWeight : "bold",
        fontSize : 18,
        drawBorder:true,
        color : "black",
        backgroundColor : "white"
    },{
        rowIndex : 3, 
        colIndex : 0, 
        rowSpan : 1,
        colSpan : colCount, 
        text : sheetTitle2, 
        textAlign : "right",
        fontSize : 12,
        drawBorder:true
    }];

    let options = {
        fileName: "월별추이실적_"+acctDeptCd + "_" + str1 + "_ver_" + lc_version.getValue()+"_하위"+".xlsx",
        sheetName: acctDeptCd.trim().replace('/',''),
        startRowIndex : 4,
        startColumnIndex : 0,
        type : 1,
        hiddenVisible : true
    }
    await $c.data.downloadGridViewExcel(gr_master, options, infoArr);     
};

//---------------------------------------------------------------------------------------
// 엑셀 Download  <하위부서 Excel Down Load : 하위부서포함한 전체 를 excel 파일로 저장 >--2007.04.17
//---------------------------------------------------------------------------------------
scwin.f_Export2 = async function (){
    var dataList = ds_multipleExcel;
    var dataListNm = "ds_multipleExcel_";

    // 생성할 데이터리스트 컬럼 세팅 
    var colInfoJSON = [];
    for (var i = 0; i < dataList.getTotalCol(); i++) {
        var colInfo = {
              "id": dataList.getColumnID(i)
            , "dataType": "text"
            , "name": dataList.getColumnName(i)
        };
        colInfoJSON.push(colInfo);
    };

    // 파일명 : ex) 월별원가실적조회_시화센터운송_202501_ver_200_하위
    var fileName = "월별추이실적_" + lc_acctDeptCd.getText(true) + "_" + ed_srchCloseYm.getValue() + "_ver_" + lc_version.getValue() + "_하위";
    // 최종 넘길 json
    var options = {
        common: {
            fileName: fileName+".xlsx",     // [default: excel.xls] 다운로드하려는 파일의 이름
            showProcess : true,             // [default: true] 다운로드 시 프로세스 창을 보여줄지 여부
            multipleSheet : "true",         // [default: true] 다운로드시 dataList별 sheet분리 출력유무
        },
        // 시트별 정보
        excelInfo: []
    };

    for (var i = 0 ; i < ds_dept.getRowCount() ; i++) {
        // 동적 생성할 데이터리스트에 담을 데이터 조회
        dma_search.set("acctDeptCd", ds_dept.getCellData(i, "col1"));
        var rs = await $c.sbm.execute(sbm_searchMonthEachResultForExcel);
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            var rowCnt = ds_master.getRowCount();
            if (rowCnt == 0 ){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
            } else {
                scwin.f_Rate();
            }
        }
        if (ds_master.getRowCount() == 0) {
			await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
			continue;
		}

        // 동적 생성할 데이터 리스트 정보
        var dsName = dataListNm;
        var dataListId = dsName + i;
        var dltObj = $c.util.getComponent(dataListId);
        if (!$c.util.isEmpty(dltObj)) {
            $p.data.remove(dataListId); // 이미생성된 데이터리스트 삭제
        }
        var dltOptions = {
              baseNode          : "list"
            , repeatNode        : "map"
            , saveRemovedData   : "true"
        };
        var dataCollectionJSON = {
            id: dataListId,
            type: "dataList",
            option: {
                "baseNode": dltOptions.baseNode || "list",
                "repeatNode": dltOptions.repeatNode || "map",
                "saveRemovedData": dltOptions.saveRemovedData || "true",
            },
            columnInfo: colInfoJSON
        };
        // 동적생성
        $p.data.create(dataCollectionJSON);
        var codeDataObj = $c.util.getComponent(dataListId);

        // 동적생성된 데이터리스트에 값 입력
        codeDataObj.setJSON(ds_master.getAllJSON());

        // 그리드 동적생성
        var idx = await gen_gridView1.insertChildAsync();
        var grdObj = $p.getComponentById(gen_gridView1.getChildren()[idx].id);
        var grdObjId = grdObj.getOriginalID();

        if ($c.gus.cfIsNull(scwin.pageNum)) scwin.pageNum = 1;
        var gr_target  = '<w2:gridView xmlns:w2="http://www.inswave.com/websquare" xmlns:ev="http://www.w3.org/2001/xml-events" '
        gr_target += '    autoFit="none" checkAllType="false" class="wq_gvw" dataList="data:' + codeDataObj.org_id + '"'
        gr_target += '    id="'+grdObjId+'" style="" visibleRowNum="13" visibleRowNumFix="true">'
        gr_target += '  <w2:caption id="caption1" style="" value="this is a grid caption."></w2:caption>'
        gr_target += '  <w2:header id="header1" style="">'
        gr_target += '		<w2:row id="row1" style="">'
        gr_target += '			<w2:column width="160" inputType="text" style="" id="column96" value="계정"'
        gr_target += '				displayMode="label" colSpan="" rowSpan="2">'
        gr_target += '			</w2:column>'
        gr_target += '			<w2:column displayMode="label" id="column1" inputType="text" value="계정" width="160"'
        gr_target += '				rowSpan="2">'
        gr_target += '			</w2:column>'
        gr_target += '			<w2:column width="60" inputType="text" style="" id="column99" value="구분" displayMode="label"'
        gr_target += '				colSpan="" rowSpan="2">'
        gr_target += '			</w2:column>'
