scwin.ds_master_ondataload = function () {    
    scwin.rowCnt = ds_master.getTotalRow();
    totalRows.setValue(scwin.rowCnt);    
	if( scwin.rowCnt == 0 ){
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
       return;
	}

    if (ds_master.getTotalRow() > 0) {
       ds_master.sort("prtPosSeq", 0);
    } 

    scwin.f_Rate();   
};


