scwin.sbm_master_submitdone = async function (e) {  
    // console.log("=====>scwin.sbm_master_submitdone");
    totalRows.setValue(ds_master.getRowCount());

    // let originalData = ds_master.getAllJSON();
    // ds_bizPlanOriginal.setJSON(originalData);
    // scwin.f_changeUnit();
    let bookClsCd = lc_srchBookClsCd.getValue();

    if(ds_master.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_ERR_003);
    }

    // 조회 완료후 장부구분의 코드값을 원 코드값으로 변경한다.
    // 일반일경우
    if ( bookClsCd === "621" ) {
        dma_searchBizPlan.set("bookClsCd","601");
    // 요약일경우
    } else if ( bookClsCd === "622" ) {
        dma_searchBizPlan.set("bookClsCd","602");
    // 상세일경우
    } else if ( bookClsCd === "623" ) {
        dma_searchBizPlan.set("bookClsCd","603");
    }
};

